arguments.argument:
if global.gamePaused=false
{
  if shiftTime>=shiftTimeMax
  {
    if shiftSeq=0
    {
      xVel=0
      yVel=0
      shiftSeq=1
    }
    else if shiftSeq>=1 and shiftSeq<=20
      shiftSeq+=1
    else if shiftSeq>=21
    {
      shiftTime=0
      shiftSeq=0
      xVel=xDir
      yVel=yDir
      xVel*=-1
      yVel*=-1
      xDir=xVel
      yDir=yVel
    }
  }
  else
  {
    if prevX!=x or prevY!=y
    {
      prevX=x
      prevY=y
      shiftTime+=1
    }
  }
  scrPlatformCrush()
}
